#[inline]
fn lowbit(x: usize) -> usize {
    x & x.wrapping_neg()
}

struct FenwTree {
    n: usize,
    tree: Vec<i64>,
}

impl FenwTree {
    pub fn new(n: usize) -> Self {
        FenwTree {
            n,
            tree: vec![0; n + 1],
        }
    }

    pub fn update(&mut self, index: usize, delta: i64) {
        let mut idx = index + 1;
        while idx <= self.n {
            self.tree[idx] += delta;
            idx += lowbit(idx);
        }
    }

    fn prefix_query(&self, index: usize) -> i64 {
        let mut sum = 0;
        let mut idx = index + 1;
        while idx > 0 {
            sum += self.tree[idx];
            idx -= lowbit(idx);
        }
        sum
    }

    pub fn range_query(&self, l: usize, r: usize) -> i64 {
        let right_sum = self.prefix_query(r);
        let left_sum = if l == 0 {
            0
        } else {
            self.prefix_query(l - 1)
        };
        right_sum - left_sum
    }
}

fn build_cache() -> Vec<usize> {
    let mut cache = vec![0; 61];
    for n in 2..=60 {
        let p = (n as u64).count_ones() as usize;
        cache[n] = 1 + cache[p];
    }
    cache
}

fn compute_depth(x: i64, cache: &[usize]) -> usize {
    if x == 1 {
        0
    } else {
        let p = x.count_ones() as usize;
        1 + cache[p]
    }
}

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut cache = build_cache();
    let n = nums.len();
    let mut depth_arr: Vec<usize> = nums.iter().map(|&x| compute_depth(x, &cache)).collect();

    let mut trees: Vec<FenwTree> = (0..6).map(|_| FenwTree::new(n)).collect();

    for (i, &d) in depth_arr.iter().enumerate() {
        if d < 6 {
            trees[d].update(i, 1);
        }
    }

    let mut ans = Vec::new();
    for q in queries {
        if q[0] == 1 {
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3] as usize;
            if k < 6 {
                let cnt = trees[k].range_query(l, r);
                ans.push(cnt);
            } else {
                ans.push(0);
            }
        } else if q[0] == 2 {
            let idx = q[1] as usize;
            let val = q[2];
            let new_d = compute_depth(val, &cache);
            let old_d = depth_arr[idx];
            if old_d < 6 {
                trees[old_d].update(idx, -1);
            }
            if new_d < 6 {
                trees[new_d].update(idx, 1);
            }
            depth_arr[idx] = new_d;
        }
    }
    ans
}
