impl Fenw {
    pub fn new(n: usize) -> Self {
        Fenw { n, tree: vec![0; n+1] }
    }

    pub fn add(&mut self, i: usize, delta: i64) {
        let mut idx = i + 1;
        while idx <= self.n {
            self.tree[idx] += delta;
            let lowbit = (idx as i32 & -(idx as i32)) as usize;
            idx += lowbit;
        }
    }

    pub fn prefix_sum(&self, i: usize) -> i64 {
        let mut i = i;
        if i >= self.n {
            i = self.n - 1;
        }
        let mut idx = i + 1;
        let mut res = 0;
        while idx > 0 {
            res += self.tree[idx];
            let lowbit = (idx as i32 & -(idx as i32)) as usize;
            idx -= lowbit;
        }
        res
    }

    pub fn query(&self, l: usize, r: usize) -> i64 {
        if l > r {
            return 0;
        }
        if l == 0 {
            self.prefix_sum(r)
        } else {
            self.prefix_sum(r) - self.prefix_sum(l-1)
        }
    }
}

