    let max_k = 6;
    let mut fenws: Vec<Fenw> = (0..max_k).map(|_| Fenw::new(n)).collect();

    for i in 0..n {
        let d = depths[i];
        if d < max_k as i32 {
            fenws[d as usize].add(i, 1);
        }
    }

