    tree: Vec<i64>,
    n: usize,
}

impl FenwTree {
    fn new(n: usize) -> Self {
        FenwTree {
            tree: vec![0; n + 1],
            n,
        }
    }

    fn update(&mut self, index: usize, delta: i64) {
        let mut idx = index + 1;
        while idx <= self.n {
            self.tree[idx] += delta;
            let lowbit = idx & idx.wrapping_neg();
            idx += lowbit;
        }
    }

    fn query_prefix(&self, index: usize) -> i64 {
        let mut idx = index + 1;
        let mut sum = 0;
        while idx > 0 {
            sum += self.tree[idx];
            let lowbit = idx & idx.wrapping_neg();
            idx -= lowbit;
        }
        sum
    }

    fn query_range(&self, l: usize, r: usize) -> i64 {
        if l > r {
            return 0;
        }
        if l == 0 {
            self.query_prefix(r)
        } else {
            self.query_prefix(r) - self.query_prefix(l - 1)
        }
    }
}

fn depth(mut x: i64) -> i32 {
    if x == 1 {
        return 0;
    }
    let mut steps = 0;
    while x != 1 {
        x = x.count_ones() as i64;
        steps += 1;
    }
    steps
}

